from order_desk.api import gather
from order_desk.basket import fill


def test_repeated_gathers_stay_isolated():
    for _ in range(5):
        assert gather(["pick"]) == ["PICK"]


def test_explicit_basket_is_extended():
    seed = ["SHIP"]
    assert fill(["pick"], seed) == ["SHIP", "PICK"]


def test_explicit_basket_does_not_touch_default():
    fill(["pack"], ["PICK"])
    assert gather(["ship"]) == ["SHIP"]


def test_whitespace_is_trimmed():
    assert gather(["  pick  "]) == ["PICK"]

